def has_close_elements(numbers: List[float], threshold: float) -> bool:
    numbers.sort() # sort the list to make it easier to find close elements
    for i in range(len(numbers)-1): 
        if abs(numbers[i] - numbers[i+1]) < threshold: # check if difference is smaller than threshold
            return True # if so, return True
    return False # if no close elements found, return False
